        'Change to switch templates without redeployment (BR-012).',
        TRUE, TRUE
    ),
    (
        'greeting.default.output_channel',
        'STDOUT',
        'STRING',
        'Channel to which generated greetings are written (BR-002). '
        'Extend to support FILE, DATABASE, API.',
        TRUE, TRUE
    ),
    (
        'greeting.recipient.trim_enabled',
        'true',
        'BOOLEAN',
        'When true, GreetingService trims whitespace from requested recipient (BR-010).',
        TRUE, TRUE
    ),
    (
        'greeting.recipient.fallback_on_blank',
        'true',
        'BOOLEAN',
        'When true, a blank recipient triggers fallback to default recipient (BR-009).',
        TRUE, TRUE
    ),
    (
        'greeting.args.use_first_only',
        'true',
        'BOOLEAN',
        'When true, only args[0] is used as recipient; later arguments are discarded (BR-006).',
        TRUE, TRUE
    );

-- ------------------------------------------------------------
-- Seed: greeting_events — canonical WF-001 "Hello World" event
-- Corresponds to HelloWorldTest.mainPrintsHelloWorldWithTrailingNewline
-- ------------------------------------------------------------
INSERT INTO greeting_events
    (
        template_id,
        recipient_id,
        requested_recipient,
        args_count,
        resolved_recipient,
        resolution_strategy,
        workflow_id,
        generated_greeting,
        output_channel
    )
SELECT
    gt.template_id,
    r.recipient_id,
    NULL,            -- no CLI argument supplied (BR-005)
    0,               -- empty args array (BR-005)
    'World',         -- default recipient resolved (BR-013)
    'DEFAULT_USED',  -- WF-001 path (BR-001, BR-008)
    'WF-001',
    'Hello World',   -- BR-012 + BR-013
    'STDOUT'         -- BR-002
FROM greeting_templates gt
CROSS JOIN recipients r
WHERE gt.template_key = 'DEFAULT_HELLO'
  AND r.recipient_name = 'World'
  AND r.is_default = TRUE;


